  ('elementary-64311456-moex-00765', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '從學校社會工作者的倫理考量中，對國一小美的處遇下列何者較適切？', '["小美有急需，可以依狀況借用金錢給她", "小美將於下課後找人對付小芳，考量與小美維持關係，可答應為其保守秘密", "告知少年保護官有關小美的最近缺課、打人的事實", "小美決定不再上學，基於案主自決原則予以尊重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
