  ('elementary-64311456-moex-00774', 'elementary-64311456', 'elementary-64311456-moex-111-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '我國老人福利已推動老人財產信託，下列那一項有關信託的敘述錯誤？', '["信託是以「財產權」為中心的法律關係", "信託是老人保護的重要方法", "人格權、身心權可以做為財產信託", "專利權、著作權可以做為財產信託"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "2fbac3fb0314", "answer_pdf_sha1": "ec43feddf564", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
